"use strict";(self.webpackChunkhcihub_docs=self.webpackChunkhcihub_docs||[]).push([[8102],{9142:e=>{e.exports=JSON.parse('{"version":{"pluginId":"default","version":"current","label":"Latest","banner":null,"badge":true,"noIndex":false,"className":"docs-version-current","isLast":true,"docsSidebars":{"tutorialSidebar":[{"type":"category","label":"datasets","collapsible":true,"collapsed":true,"items":[{"type":"category","label":"invasive","collapsible":true,"collapsed":true,"items":[{"type":"link","label":"1_FALCON M1-A","href":"/BCIJelly-site/docs/datasets/invasive/FALCON-M1-A","docId":"datasets/invasive/FALCON-M1-A","unlisted":false},{"type":"link","label":"2_FALCON M2","href":"/BCIJelly-site/docs/datasets/invasive/FALCON M2","docId":"datasets/invasive/FALCON M2","unlisted":false},{"type":"link","label":"3_Finger RL","href":"/BCIJelly-site/docs/datasets/invasive/Finger RL","docId":"datasets/invasive/Finger RL","unlisted":false},{"type":"link","label":"4_Finger PPC","href":"/BCIJelly-site/docs/datasets/invasive/Finger PPC","docId":"datasets/invasive/Finger PPC","unlisted":false},{"type":"link","label":"5_Jango","href":"/BCIJelly-site/docs/datasets/invasive/Jango","docId":"datasets/invasive/Jango","unlisted":false},{"type":"link","label":"6_LINK","href":"/BCIJelly-site/docs/datasets/invasive/LINK","docId":"datasets/invasive/LINK","unlisted":false},{"type":"link","label":"7_NPR M1","href":"/BCIJelly-site/docs/datasets/invasive/NPR M1","docId":"datasets/invasive/NPR M1","unlisted":false},{"type":"link","label":"8_Reaching MC PMC","href":"/BCIJelly-site/docs/datasets/invasive/Reaching MC PMC","docId":"datasets/invasive/Reaching MC PMC","unlisted":false},{"type":"link","label":"9_Visual Neuropixel","href":"/BCIJelly-site/docs/datasets/invasive/Visual Neuropixel","docId":"datasets/invasive/Visual Neuropixel","unlisted":false},{"type":"link","label":"10_Visual Grating Task","href":"/BCIJelly-site/docs/datasets/invasive/Visual Grating Task","docId":"datasets/invasive/Visual Grating Task","unlisted":false},{"type":"link","label":"11_Speech","href":"/BCIJelly-site/docs/datasets/invasive/Speech","docId":"datasets/invasive/Speech","unlisted":false},{"type":"link","label":"12_Music","href":"/BCIJelly-site/docs/datasets/invasive/Music","docId":"datasets/invasive/Music","unlisted":false},{"type":"link","label":"13_Emotion","href":"/BCIJelly-site/docs/datasets/invasive/Emotion","docId":"datasets/invasive/Emotion","unlisted":false}]},{"type":"category","label":"non-invasive","collapsible":true,"collapsed":true,"items":[{"type":"link","label":"1_BOLD5000","href":"/BCIJelly-site/docs/datasets/non-invasive/BOLD5000","docId":"datasets/non-invasive/BOLD5000","unlisted":false},{"type":"link","label":"2_GOD","href":"/BCIJelly-site/docs/datasets/non-invasive/GOD","docId":"datasets/non-invasive/GOD","unlisted":false},{"type":"link","label":"3_EEGMMI","href":"/BCIJelly-site/docs/datasets/non-invasive/EEGMMI","docId":"datasets/non-invasive/EEGMMI","unlisted":false},{"type":"link","label":"4_SEED IV","href":"/BCIJelly-site/docs/datasets/non-invasive/SEED IV","docId":"datasets/non-invasive/SEED IV","unlisted":false},{"type":"link","label":"5_SEED VII","href":"/BCIJelly-site/docs/datasets/non-invasive/SEED-VII","docId":"datasets/non-invasive/SEED-VII","unlisted":false},{"type":"link","label":"6_Things EEG","href":"/BCIJelly-site/docs/datasets/non-invasive/Things EEG","docId":"datasets/non-invasive/Things EEG","unlisted":false},{"type":"link","label":"7_Calcium Imaging","href":"/BCIJelly-site/docs/datasets/non-invasive/Calcium Imaging","docId":"datasets/non-invasive/Calcium Imaging","unlisted":false}]}]},{"type":"category","label":"models","collapsible":true,"collapsed":true,"items":[{"type":"link","label":"1_LSTM","href":"/BCIJelly-site/docs/models/LSTM","docId":"models/LSTM","unlisted":false},{"type":"link","label":"2_Transformer","href":"/BCIJelly-site/docs/models/transformer","docId":"models/transformer","unlisted":false},{"type":"link","label":"3_LFADS","href":"/BCIJelly-site/docs/models/lfads","docId":"models/lfads","unlisted":false},{"type":"link","label":"4_Stabilization","href":"/BCIJelly-site/docs/models/stabilization","docId":"models/stabilization","unlisted":false},{"type":"link","label":"5_Cycle-GAN","href":"/BCIJelly-site/docs/models/Cycle_GAN","docId":"models/Cycle_GAN","unlisted":false},{"type":"link","label":"6_Language LSTM","href":"/BCIJelly-site/docs/models/languageLSTM","docId":"models/languageLSTM","unlisted":false},{"type":"link","label":"7_Language Transformer","href":"/BCIJelly-site/docs/models/languageTransformer","docId":"models/languageTransformer","unlisted":false}]}]},"docs":{"datasets/invasive/Emotion":{"id":"datasets/invasive/Emotion","title":"13_Emotion","description":"Repository Link\uff1ahttps://neurotycho.org/emotional-movie-task","sidebar":"tutorialSidebar"},"datasets/invasive/FALCON M2":{"id":"datasets/invasive/FALCON M2","title":"2_FALCON M2","description":"This project provides a complete preprocessing pipeline for the FALCON Benchmark M2 dataset, which contains neural recordings from the primary motor cortex in non-human primates during finger movement tasks.","sidebar":"tutorialSidebar"},"datasets/invasive/FALCON-M1-A":{"id":"datasets/invasive/FALCON-M1-A","title":"1_FALCON M1-A","description":"Repository Link\uff1ahttps://snel-repo.github.io/falcon/","sidebar":"tutorialSidebar"},"datasets/invasive/Finger PPC":{"id":"datasets/invasive/Finger PPC","title":"4_Finger PPC","description":"PPC_Finger (human posterior parietal cortex recordings during attempted finger movements)","sidebar":"tutorialSidebar"},"datasets/invasive/Finger RL":{"id":"datasets/invasive/Finger RL","title":"3_Finger RL","description":"The Finger_RL dataset contains single-neuron recordings from two tetraplegic human participants attempting individual finger movements.","sidebar":"tutorialSidebar"},"datasets/invasive/Jango":{"id":"datasets/invasive/Jango","title":"5_Jango","description":"Data Source: Using adversarial networks to extend brain computer interface decoding accuracy over time (Dryad dataset). Includes data from multiple monkeys across different tasks (ISO/CO/RT/PG).","sidebar":"tutorialSidebar"},"datasets/invasive/LINK":{"id":"datasets/invasive/LINK","title":"6_LINK","description":"Dataset Link\uff1ahttps://github.com/chesteklab/LINK_dataset","sidebar":"tutorialSidebar"},"datasets/invasive/Music":{"id":"datasets/invasive/Music","title":"12_Music","description":"This project provides a kind of preprocessing Data from: Nonlinear decoding models enable music reconstruction from human auditory cortex activity dataset in the way that raw signals are transformed into signals for model training. The dataset contains intracranial electroencephalogram (ECoG) data recorded from 29 patients with drug-resistant epilepsy while passively listening to Pink Floyd songs. The dataset contains preprocessed neural activity (high-frequency activity, 70-150 Hz), electrode coordinates (MNI template space), and auditory stimuli (raw waveform files, and auditory spectrograms at 32 and 128 frequency points). The HFA and the two auditory spectrograms were sampled at 100 Hz and temporally aligned (190.72 seconds duration).","sidebar":"tutorialSidebar"},"datasets/invasive/NPR M1":{"id":"datasets/invasive/NPR M1","title":"7_NPR M1","description":"This dataset is sourced from Zenodo Record 3854034, which contains invasive neural recordings from the primary motor cortex (M1) of non-human primates performing a center-out cursor control task. The neural data were recorded using a 192-channel Utah array, and the behavioral data consist of 2D cursor positions and corresponding target positions. Each .mat file corresponds to one recording session.","sidebar":"tutorialSidebar"},"datasets/invasive/Reaching MC PMC":{"id":"datasets/invasive/Reaching MC PMC","title":"8_Reaching MC PMC","description":"Long-term Recordings of Motor and Premotor Cortical Spiking Activity During Reaching in Monkeys","sidebar":"tutorialSidebar"},"datasets/invasive/Speech":{"id":"datasets/invasive/Speech","title":"11_Speech","description":"This project provides A way to preprocess the Data for: A high-performance speech neuroprosthesis dataset to transform raw signals into signals for model training. The dataset consists of 12,100 sentences spoken by a single study participant. We use the \\"competitionData\\" version of it, which is a simplified version of the sentence data formatted and partitioned for machine learning research. It contains \\"train\\" and \\"test\\" partitions for model development, and a reserved \\"competitionHoldOut\\" set for the speech decoding competition (labels will be released after the competition). We currently only use the train (8800) versus test (880) partition data. For each sentence, a transcript of what the participant was trying to say was provided, along with a corresponding time series of neural spike activity recorded from 256 microelectrodes in speech related areas of the cortex.","sidebar":"tutorialSidebar"},"datasets/invasive/Visual Grating Task":{"id":"datasets/invasive/Visual Grating Task","title":"10_Visual Grating Task","description":"This project provides a complete preprocessing pipeline for Visual Grating Task ECoG recordings from neurotycho.org.","sidebar":"tutorialSidebar"},"datasets/invasive/Visual Neuropixel":{"id":"datasets/invasive/Visual Neuropixel","title":"9_Visual Neuropixel","description":"Allen Brain Observatory \u2014 Visual Coding Neuropixels dataset (NWB, downloaded via AllenSDK). This dataset contains 58 experiments, each with up to 6 Neuropixels probes covering cortical, thalamic, and hippocampal regions, and is designed for systematic study of the mouse visual system under passive stimulation. This workflow uses drifting gratings (8 orientations) as an example, showing the complete process of session selection, unit filtering, spike matrix construction, time binning, and data saving. The official documentation describes the 8 orientations and temporal/spatial frequency settings in detail.","sidebar":"tutorialSidebar"},"datasets/non-invasive/BOLD5000":{"id":"datasets/non-invasive/BOLD5000","title":"1_BOLD5000","description":"This project aims to conduct standardized preprocessing on the BOLD5000 dataset, extract fMRI features and perform dimensionality transformation, providing high-quality input features and corresponding labels for subsequent model training related to visual cognition (such as image classification, brain activity prediction, etc.).","sidebar":"tutorialSidebar"},"datasets/non-invasive/Calcium Imaging":{"id":"datasets/non-invasive/Calcium Imaging","title":"7_Calcium Imaging","description":"Repository Link\uff1ahttps://zenodo.org/doi/10.5281/zenodo.10408334","sidebar":"tutorialSidebar"},"datasets/non-invasive/EEGMMI":{"id":"datasets/non-invasive/EEGMMI","title":"3_EEGMMI","description":"This project provides a way to preprocess the EEG Motor Movement/Imagery dataset by transforming raw EEG signals into signals for model training. Only two subsets of the EEG Motor Movement/Imagery dataset were used in the project. The first subset contains only performed left or right hand motor tasks. The second subset contains only imagined left or right hand motor tasks. In both subsets, a total of 103 out of 109 subjects were used, and subjects 38, 88, 89, 92, 100, and 104 were omitted due to data annotation errors.","sidebar":"tutorialSidebar"},"datasets/non-invasive/GOD":{"id":"datasets/non-invasive/GOD","title":"2_GOD","description":"Based on the requirements of the classification task, we only use the perceptionTraining subset (150 categories \xd7 8 images = 1,200 natural images). This subset has undergone standard fMRI preprocessing in the original paper, including head motion correction, spatial registration, and global normalization, making it suitable for subsequent training-test splitting.","sidebar":"tutorialSidebar"},"datasets/non-invasive/SEED IV":{"id":"datasets/non-invasive/SEED IV","title":"4_SEED IV","description":"Repository Link\uff1aSEED-IV Dataset Official Website","sidebar":"tutorialSidebar"},"datasets/non-invasive/SEED-VII":{"id":"datasets/non-invasive/SEED-VII","title":"5_SEED VII","description":"Repository Link\uff1ahttps://bcmi.sjtu.edu.cn/~seed/seed-vii.html","sidebar":"tutorialSidebar"},"datasets/non-invasive/Things EEG":{"id":"datasets/non-invasive/Things EEG","title":"6_Things EEG","description":"This project provides a preprocessing method for the THINGS-EEG dataset, transforming raw EEG signals into model-ready data. The dataset contains high-temporal-resolution EEG responses from 10 participants to naturalistic object images, recorded using a Rapid Serial Visual Presentation (RSVP) paradigm.","sidebar":"tutorialSidebar"},"models/Cycle_GAN":{"id":"models/Cycle_GAN","title":"5_Cycle-GAN","description":"I. Model Overview","sidebar":"tutorialSidebar"},"models/languageLSTM":{"id":"models/languageLSTM","title":"6_Language LSTM","description":"I. Model Introduction","sidebar":"tutorialSidebar"},"models/languageTransformer":{"id":"models/languageTransformer","title":"7_Language Transformer","description":"I. Model Introduction","sidebar":"tutorialSidebar"},"models/lfads":{"id":"models/lfads","title":"3_LFADS","description":"I. Model Overview","sidebar":"tutorialSidebar"},"models/LSTM":{"id":"models/LSTM","title":"1_LSTM","description":"I. Model Overview","sidebar":"tutorialSidebar"},"models/stabilization":{"id":"models/stabilization","title":"4_Stabilization","description":"I. Model Overview","sidebar":"tutorialSidebar"},"models/transformer":{"id":"models/transformer","title":"2_Transformer","description":"I. Model Overview","sidebar":"tutorialSidebar"}}}}')}}]);